<template>
    <v-container id="blog">
        <v-layout row wrap justify-center>
            <v-flex v-for="item in issues" :key="item.id" xs12 md8>
                <v-card class="list mt-3" :to="'/detail/' + item.number" exact append>
                    <v-card-title class="pb-0" primary-title>
                        <h4 class="headline mb-0 d-flex">
                            <span class="d-flex">{{item.title}}</span>
                            <div class="d-flex">
                                <v-item-group class="tags" dark>
                                    <v-item v-for="label in item['labels']" :key="label.id" disabled>
                                        <v-chip slot-scope="{ active, toggle }" text-color="#ffffff80" small light outline disabled>
                                            <v-icon class="mr-2" small>local_offer</v-icon>
                                            {{ label.name }}
                                        </v-chip>
                                    </v-item>
                                </v-item-group>
                            </div>
                        </h4>
                        <div class="introduction">{{item.body | str}}</div>
                    </v-card-title>

                    <v-card-actions class="actions">
                        <div class="mr-5">
                            <v-icon small>create</v-icon>
                            <span class="ml-1">创建时间：{{item['created_at'] | time}}</span>
                        </div>
                        <div>
                            <v-icon small>comment</v-icon>
                            <span class="ml-1">评论：{{item.comments}}</span>
                        </div>
                    </v-card-actions>
                </v-card>
            </v-flex>
        </v-layout>
        <v-layout>
            <v-flex>
                <div class="text-xs-center">
                    <v-pagination v-model="page" :length="pageLen" @input="changeSize" dark></v-pagination>
                </div>
            </v-flex>
        </v-layout>
    </v-container>
</template>

<script>
    import dayjs from 'dayjs';

    export default {
        name: "Blog",
        data() {
            return {
                issues: [],
                page: 1, // 当前页
                pageLen: 0, // 总页数
                pageLimit: 10, // 每页10条
                allItemsLen: 0, // 所有条数
                allItemsPage: 1, // 所有页数
            }
        },
        filters: {
            str(val) {
                const reg = /[`~!@#$^&*=|{}',<>\/?~！@#￥……&*——|]/g;
                let res = val.slice(0, 300);
                return res.replace(reg, ' ');
            },
            time(val) {
                return dayjs(val).format('YYYY-MM-DD');
            }
        },
        methods: {
            getIssues() {
                const url = 'https://api.github.com/repos/hhp1614/blog/issues';
                const token = `${this.$store.state.githubToken[0]}${this.$store.state.githubToken[1]}`;
                const sort = 'created';
                const filter = 'created';
                const req = `${url}?access_token=${token}&&page=${this.page}&&per_page=${this.pageLimit}&&sort=${sort}&&filter=${filter}`;
                this.$axios.get(req).then(res => {
                    this.issues = res.data;
                }).catch((err) => {
                    console.log(err);
                });
            },
            getIssuesPageLen() {
                const url = 'https://api.github.com/repos/hhp1614/blog/issues';
                const token = `${this.$store.state.githubToken[0]}${this.$store.state.githubToken[1]}`;
                const sort = 'created';
                const filter = 'created';
                const req = `${url}?access_token=${token}&&sort=${sort}&&filter=${filter}&&page=${this.allItemsPage}&&per_page=100`;
                this.$axios.get(req).then(res => {
                    this.allItemsLen += res.data.length;
                    if (res.data.length >= 100) {
                        this.allItemsPage++;
                        this.getIssuesPageLen();
                    }
                    this.pageLen += Math.ceil(this.allItemsLen / this.pageLimit);
                }).catch((err) => {
                    console.log(err);
                });
            },
            changeSize(page) {
                this.page = page;
                this.getIssues();
            }
        },
        created() {
            this.getIssuesPageLen();
            this.getIssues();
        }
    }
</script>

